SELECT name
FROM hbase_tables
WHERE read_requests > 500;

SELECT name, read_requests
FROM hbase_tables
ORDER BY read_requests DESC;

SELECT SUM(read_requests) AS total_read_requests
FROM hbase_tables
WHERE table_id = 1;

SELECT MAX(access_date) AS most_recent_access
FROM access_logs
WHERE table_id = (SELECT table_id FROM hbase_tables WHERE name = 'users_table');
